class DryerBox { public double TargetTemp { get; } public double CurrentTemp { get; set; } public DryerBox(double t) { TargetTemp = t; } }

var lineA = new DryerBox(85); lineA.CurrentTemp = 84.2;
var lineB = new DryerBox(92); lineB.CurrentTemp = 91.8;
var lineC = new DryerBox(78); lineC.CurrentTemp = 77.5;

var lines = new List<DryerBox>();
lines.Add(lineA); lines.Add(lineB); lines.Add(lineC);

foreach (var line in lines)
    Print($"目标:{line.TargetTemp}°C 当前:{line.CurrentTemp}°C");
